def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            val = abs(ratio)
            penalty = 0
            for p in range(1, 5):
                penalty += (val ** (2*p)) / (p * 3)
            priorities[i] = penalty + val * 7
        elif ratio > 1:
            penalty = 0
            for k in range(1, 6):
                penalty += np.sin(ratio * k) / (k + 1)
            priorities[i] = ratio ** 4 + penalty * 3
            if ratio > 2:
                penalty2 = 0
                for q in range(1, 4):
                    penalty2 += (np.log1p(ratio) ** q) / (q + 2)
                priorities[i] += penalty2 * 5
        else:
            score = 0
            for j in range(1, 7):
                sign = 1 if j % 3 == 0 else (-1 if j % 2 == 0 else 1)
                term = sign * (ratio ** j) / (j + 1)
                score += term
            multiplier = 20 if ratio < 0.2 else 12 if ratio < 0.5 else 8 if ratio < 0.75 else 4
            priorities[i] = abs(score) * multiplier
            if 0.5 < ratio <= 0.9:
                extra = 0
                for m in range(1, 5):
                    extra += (ratio ** (2 * m)) / (m * 3)
                priorities[i] += extra
            if 0.85 < ratio <= 1:
                correction = 0
                for r in range(1, 4):
                    correction += ((-1) ** r) * (ratio ** (r * 3)) / (r + 1)
                priorities[i] += abs(correction) * 2
            if ratio == 0.5:
                priorities[i] *= 0.85
    return priorities
